import httpx
from tenacity import (
    retry, stop_after_attempt, wait_exponential_jitter,
    retry_if_exception, before_sleep_log
)
import logging

logger = logging.getLogger(__name__)

RETRYABLE_STATUS = {429, 500, 502, 503, 504}

def should_retry(exc: BaseException) -> bool:
    if isinstance(exc, httpx.HTTPStatusError):
        return exc.response.status_code in RETRYABLE_STATUS
    return isinstance(exc, (httpx.ConnectError, httpx.TimeoutException))

def respect_retry_after(exc: BaseException) -> float | None:
    if isinstance(exc, httpx.HTTPStatusError):
        header = exc.response.headers.get("Retry-After")
        if header:
            try:
                return float(header)
            except ValueError:
                pass
    return None

@retry(
    stop=stop_after_attempt(4),
    wait=wait_exponential_jitter(initial=1, max=30, jitter=2),
    retry=retry_if_exception(should_retry),
    before_sleep=before_sleep_log(logger, logging.WARNING),
    reraise=True,
)
def call_api_with_retry(client: httpx.Client, url: str) -> dict:
    response = client.get(url)
    response.raise_for_status()
    return response.json()

class APIClientError(Exception):
    """Base class for API client errors."""

class ClientError(APIClientError):
    """4xx errors — do not retry."""
    def __init__(self, status: int, detail: str):
        self.status = status
        super().__init__(f"HTTP {status}: {detail}")

class NotFoundError(ClientError): pass
class AuthenticationError(ClientError): pass
class RateLimitError(ClientError):
    def __init__(self, retry_after: float | None = None):
        self.retry_after = retry_after
        super().__init__(429, "Rate limit exceeded")

class ServerError(APIClientError):
    """5xx errors — retryable."""
    def __init__(self, status: int, detail: str):
        self.status = status
        super().__init__(f"Server error HTTP {status}: {detail}")

def classify_http_error(exc: httpx.HTTPStatusError) -> APIClientError:
    status = exc.response.status_code
    try:
        body = exc.response.json()
        detail = body.get("detail", body.get("message", str(exc)))
    except Exception:
        detail = str(exc)
    if status == 401:
        return AuthenticationError(status, detail)
    if status == 404:
        return NotFoundError(status, detail)
    if status == 429:
        retry_after = exc.response.headers.get("Retry-After")
        return RateLimitError(float(retry_after) if retry_after else None)
    if status >= 500:
        return ServerError(status, detail)
    return ClientError(status, detail)

from myapp.api_client import UserService, NotFoundError, ServerError

def get_user_tool(user_id: int) -> dict:
    """Tool for the agent to retrieve user information."""
    with UserService() as svc:
        try:
            user = svc.get_user(user_id)
            return {"status": "ok", "user": user.model_dump()}
        except NotFoundError:
            return {"status": "error", "code": "not_found",
                    "message": f"No user with id {user_id}"}
        except ServerError as e:
            # Agent should retry or escalate
            return {"status": "error", "code": "server_error",
                    "message": str(e), "retryable": True}
